import React from 'react';
import { Link } from 'react-router-dom';
import "./Yazan.css";



import "./Yazan.css";

const Navbar = () => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <nav className={`navbar ${scrolled ? "scrolled" : ""}`}>
      <div className="navbar-container">
        {/* Right: Logo */}
        <div className="navbar-logo">
          <span className="logo-icon">🎓</span>
          <span className="logo-text">مستشارك الأكاديمي الذكي</span>
        </div>

        {/* Left: Links + CTA */}
        <div className="navbar-links">
          <a href="!" className="nav-link">تحميل دخول</a>
          <a href="!" className="nav-link">تسجل دخول</a>
          <button className="btn-primary">ابدأ الاختبار</button>
          <span className="hamburger">☰</span>
        </div>
      </div>
    </nav>
  );
};

const HeroSection = () => (
  <section className="hero">
    <div className="hero-container">
      {/* Right: Text */}
      <div className="hero-text">
        <h1 className="hero-title">
          اكتشف تخصصك الذكي
          <br />
          <span className="highlight">مع مساعدك AI</span>
        </h1>
        <p className="hero-subtitle">
          تحليل ميولك ومهاراتك واقتراح أفضل تخصص لك
        </p>
        <button className="btn-green">ابدأ التحليل الذكي</button>
      </div>

      {/* Left: Illustration */}
      <div className="hero-illustration">
        <div className="illustration-blob"></div>
        <div className="robot-card">
          <div className="robot-face">🤖</div>
          <div className="robot-cap">🎓</div>
        </div>
        <div className="student-card">
          <span className="student-icon">🧑‍💻</span>
        </div>
        <div className="floating-card card-1">📊</div>
        <div className="floating-card card-2">✅</div>
        <div className="floating-card card-3">💡</div>
      </div>
    </div>
  </section>
);

const HowItWorks = () => {
  const cards = [
    {
      icon: "⚙️",
      title: "تحليل تخصة فوري",
      desc: "تحليل من الحرب وتحرك مهاراتك",
    },
    {
      icon: "🔍",
      title: "اقتراح تخصصات مخصصة",
      desc: "نحب تخفيف حملتك",
      badge: "VS",
    },
    {
      icon: "🤖",
      title: "محاكاة ستفيلية",
      desc: "مناسب أكثر لمهاراتك الحشوة لة",
    },
  ];

  return (
    <section className="how-it-works">
      <h2 className="section-title">كيف يعمل الموقع ؟</h2>
      <div className="cards-grid">
        {cards.map((card, i) => (
          <div className="feature-card" key={i}>
            {card.badge && <span className="vs-badge">{card.badge}</span>}
            <div className="card-icon">{card.icon}</div>
            <h3 className="card-title">{card.title}</h3>
            <p className="card-desc">{card.desc}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

const ComparisonBanner = () => (
  <section className="comparison-banner">
    <div className="comparison-inner">
      <div className="comp-right">
        <span className="comp-icon">🎓</span>
        <span className="comp-text">علوم الحاسوب – علوم السيبوب AI</span>
      </div>
      <div className="vs-circle">VS</div>
      <div className="comp-left">
        <span className="comp-check">✅</span>
        <span className="comp-text">علوم الحاسوب</span>
        <span className="comp-label">التملدي</span>
      </div>
    </div>
  </section>
);

const ChatbotButton = () => (
  <button className="chatbot-btn" title="تحدث معنا">
    💬
  </button>
);

const YazanHomePage = () => {
  return (
    <div className="app" dir="rtl">
      <Navbar />
      <HeroSection />
      <HowItWorks />
      <ComparisonBanner />
      <ChatbotButton />
    </div>
  );
};

export default YazanHomePage;
